/**
 * Admin walk-through evidence — screenshot + recording per admin page so
 * SOX §404 process-walk-through documentation can be regenerated by re-running
 * the suite instead of being captured by hand.
 *
 * Coverage is driven *strictly from Payload* — the route list is derived from
 * `payload.config.collections` and `payload.config.globals` at module load.
 * Adding a new collection automatically extends the evidence pack on the next
 * run; removing one stops emitting that PNG.
 *
 * Each test owns one admin route and produces:
 *   - `tests/evidence/admin-pages/<slug>.png` (full-page PNG)
 *   - `tests/evidence/videos/admin-evidence.e2e/<test>.webm` (recording)
 *   - `tests/evidence/traces/admin-evidence.e2e/<test>.zip`  (Playwright trace)
 *
 * The Level-1 seed suite runs once in `beforeAll` so list views render with
 * realistic rows (host / GL accounts / users / currency rates) instead of
 * empty placeholders. Every other admin page is captured empty unless a
 * higher-level seed has covered it — the seeds are the single source of
 * truth for "what data should exist in evidence captures".
 *
 * Per Payload e2e convention (`tests/e2e/admin.e2e.spec.ts`), each test does
 * its own login.
 *
 * @standard ISO/IEC-29119:2022 software-testing system-test-level
 * @standard ISO/IEC-29119-3:2021 test-documentation
 * @standard W3C WebDriver-BiDi browser-automation
 * @audit ISO-19011:2018 audit-trail visual-evidence
 * @compliance SOX §404 internal-controls process-walk-through
 * @security ISO-27001 A.5.16 identity-management
 * @security ISO-27001 A.5.17 authentication-information
 * @see tests/helpers/evidence.ts
 * @see src/plugins/accounting/seeds/level-1
 * @see docs/STANDARDS.md §4.4 §7
 */

import { test } from '@playwright/test'
import { getPayload } from 'payload'
import configPromise from '@payload-config'

import { login } from '../helpers/login'
import { testUser } from '../helpers/seedUser'
import { captureAdminPage } from '../helpers/evidence'

// ─── Resolve the admin-route surface from Payload itself ─────────────────
//
// Top-level await — supported by Playwright's ESM test loader. Importing
// `@payload-config` and resolving its promise gives us the canonical list
// of collection + global slugs without maintaining a parallel literal.

const config = await configPromise
const collectionSlugs: ReadonlyArray<string> = config.collections.map((c) => c.slug)
const globalSlugs: ReadonlyArray<string> = (config.globals ?? []).map((g) => g.slug)

interface EvidencePage {
  /** Admin URL (relative to baseURL). */
  readonly route: string
  /** Filename + label for the captured PNG. */
  readonly label: string
}

const collectionPages: ReadonlyArray<EvidencePage> = collectionSlugs.map((slug) => ({
  route: `/admin/collections/${slug}`,
  label: `collections-${slug}`,
}))

const globalPages: ReadonlyArray<EvidencePage> = globalSlugs.map((slug) => ({
  route: `/admin/globals/${slug}`,
  label: `globals-${slug}`,
}))

const ADMIN_PAGES: ReadonlyArray<EvidencePage> = [
  { route: '/admin', label: 'dashboard' },
  ...collectionPages,
  ...globalPages,
]

// ─── Spec ────────────────────────────────────────────────────────────────

test.describe('Admin walk-through evidence', () => {
  test.describe.configure({ timeout: 60_000 })

  // One-time seed so the captured list views render with rows instead of
  // empty placeholders. Idempotent at the suite level — failures here are
  // surfaced but don't stop individual route captures, which still document
  // the empty state.
  test.beforeAll(async () => {
    try {
      // Level1SeedSuite was removed with the accounting plugin; boot Payload to
      // verify config, then capture routes against the (possibly empty) tenant.
      await getPayload({ config: configPromise })
    } catch (error) {
            console.warn(
        '[admin-evidence] Level1SeedSuite seed failed; capturing empty pages.',
        error,
      )
    }
  })

  for (const { route, label } of ADMIN_PAGES) {
    test(`captures ${label}`, async ({ page }, testInfo) => {
      await login({ page, user: testUser })
      await captureAdminPage(page, `http://localhost:3000${route}`, testInfo, label)
    })
  }
})
